import { useEffect, useState } from "react";
import { fetchPubMedResearch } from "../services/pubmedService";
import "./ResearchTicker.css";

export default function ResearchTicker() {
  const fallbackItems = [
    "Decision-making styles and personality traits",
    "Introversion vs cognitive load",
    "Judging vs Perceiving behavior patterns",
    "Emotional intelligence and stress response",
    "Cognitive preferences in problem-solving",
  ];

  const [research, setResearch] = useState([]);

  useEffect(() => {
    fetchPubMedResearch()
      .then((data) => {
        // თუ მონაცემი დაბრუნდა, ჩავსვათ მას
        if (data && data.length) setResearch(data);
      })
      .catch((err) => console.error("PubMed error:", err));
  }, []);

  // იმ შემთხვევაში, თუ რეალური მონაცემი ჯერ არ ჩამოვიდა
  const displayItems =
    research.length > 0
      ? research.map((item) => ({ title: item.title, link: item.link }))
      : fallbackItems.map((text) => ({ title: text }));

  return (
    <div className="research-ticker">
      <span>Research preview:</span>
      <div className="ticker-scroll">
        {displayItems.map((item, i) =>
          item.link ? (
            <a key={i} href={item.link} target="_blank" rel="noreferrer">
              • {item.title}
            </a>
          ) : (
            <span key={i}>• {item.title}</span>
          )
        )}
        {/* დუბლირება გრძელსლაიდისთვის marquee-ის ეფექტისთვის */}
        {displayItems.map((item, i) =>
          item.link ? (
            <a key={"dup-" + i} href={item.link} target="_blank" rel="noreferrer">
              • {item.title}
            </a>
          ) : (
            <span key={"dup-" + i}>• {item.title}</span>
          )
        )}
      </div>
    </div>
  );
}
